package core_java;

public class ExplicitCasting {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		
//	      	implicit casting
		int a=10;
		double b=a;
		
		System.out.println("a="+a);
		System.out.println("b="+b);
		
		
//      explicit casting 
		
		double d=35.00;
		int i=10;
		System.out.println("d="+d);
		System.out.println("i="+i);
		

	}

}
